<template>
    <div class="page" v-loading="loading">
        <div class="search between">
            <div></div>
            <el-button type="primary" @click="toPath('/notice/detail', null, '1')">新增</el-button>
        </div>
        <el-table :data="tableData" border style="width: 100%; margin-bottom: 20px;" row-key="id"
            :default-expand-all="false" :tree-props="{children: 'children', hasChildren: 'hasChildren'}">
            
            <el-table-column label="序号" type="index" width="50"></el-table-column>

            <el-table-column label="订单号" prop="orderid"  width="240"></el-table-column>

            <el-table-column label="商品图片" width="120"  header-align="center" align="center">
                <template slot-scope="scope">
                    <img :src="scope.row.imageurl || ''" alt="" style="width: 80px; height: 80px; border-radius: 50%; margin: auto">
                </template>
            </el-table-column>

            <el-table-column v-for="item in column1" :key="item.index"  header-align="center"  align="center"
                :prop="item.prop" :label="item.label" :width="item.width">
            </el-table-column>

            <!-- <el-table-column label="下单用户头像" width="120"  header-align="center" align="center">
                <template slot-scope="scope">
                    <img :src="scope.row.user.avatarUrl || ''" alt="" style="width: 80px; height: 80px; border-radius: 50%; margin: auto">
                </template>
            </el-table-column> -->
            
            <el-table-column v-for="item in column2" :key="item.index"  header-align="center"  align="center"
                :prop="item.prop" :label="item.label" :width="item.width">
            </el-table-column>
            
            <el-table-column fixed="right" label="操作" width="200"  header-align="center" align="center">
                <template slot-scope="scope">
                    <div v-if="!scope.row.parentid" class="around">
                        <el-button type="text" size="small" @click="changeStatus(scope.row.id, 2, scope.row.userid)" v-if="scope.row.type === 1">已入库</el-button>
                        <el-button type="text" size="small" @click="showForm(scope.row)" v-if="scope.row.type === 3">计算尾款</el-button>
                        <el-button type="text" size="small" @click="showSendForm(scope.row)" v-if="scope.row.type === 5">发货</el-button>
                    </div>
                </template>
            </el-table-column>
        </el-table>


        <div class="between">
            <p></p>
            <p></p>
            <el-pagination
                @size-change="handleSizeChange"
                @current-change="handleCurrentChange"
                :current-page="1"
                :page-sizes="[5, 10, 30, 50]"
                :page-size="5"
                layout="total, sizes, prev, pager, next, jumper"
                :total="total"
            >
            </el-pagination>
        </div>

        <el-dialog
            :title="'订单号: ' + currentRow.orderid"
            :visible.sync="dialogVisible"
            width="800px"
            :before-close="handleClose"
        >
            <el-form ref="form" :model="form" label-width="120px">
                <el-form-item label="代购费">
                    <el-input v-model="form.agentFee" type="number"></el-input>
                </el-form-item>
                <el-form-item label="日本邮费">
                    <el-input v-model="form.jpPostage" type="number"></el-input>
                </el-form-item>
                <el-form-item label="国际运费">
                    <el-input v-model="form.internationalPostage" type="number"></el-input>
                </el-form-item>
                <el-form-item label="仓储费">
                    <el-input v-model="form.storageCharge" type="number"></el-input>
                </el-form-item>
                <el-form-item label="包装费">
                    <el-input v-model="form.packingCharge" type="number"></el-input>
                </el-form-item>
                <el-form-item label="其他费用">
                    <el-input v-model="form.otherCharge" type="number"></el-input>
                </el-form-item>
                <el-form-item label="其他费用备注">
                    <el-input v-model="form.otherChargeMarks" type="textarea" :rows="4"></el-input>
                </el-form-item>
                <el-form-item>
                    <el-button type="primary" @click="onSubmit">确认</el-button>
                    <el-button @click="handleClose">取消</el-button>
                    <!-- <el-button @click="handleClose2">取消</el-button> -->
                </el-form-item>
            </el-form>
        </el-dialog>

        <el-dialog
            :title="'订单号: ' + currentRow.orderid"
            :visible.sync="dialogVisible2"
            width="800px"
            :before-close="handleClose2"
        >
            <el-form ref="form" :model="sendForm" label-width="120px">
                <el-form-item label="物流公司">
                    <el-input v-model="sendForm.expressDeliveryCompany" type="text"></el-input>
                </el-form-item>
                <el-form-item label="物流单号">
                    <el-input v-model="sendForm.expressDeliveryNo" type="text"></el-input>
                </el-form-item>
                <el-form-item label="备注">
                    <el-input v-model="sendForm.remarks" type="textarea" :rows="4"></el-input>
                </el-form-item>
                <el-form-item>
                    <el-button type="primary" @click="onSendFormSubmit">确认</el-button>
                    <el-button @click="handleClose2">取消</el-button>
                    <!-- <el-button @click="handleClose2">取消</el-button> -->
                </el-form-item>
            </el-form>
        </el-dialog>

    </div>
</template>
  
<script>
import {queryMercariOrderList, updataMercariOrderStatus, countCost, sendGood} from "@/http/api"

export default {
    data(){
        return {
            hasChildren: true,
            loading: false,
            column1: [
                { label: "商品标题", prop: "title", width: "200" },
                { label: "商品id", prop: "goodCode", width: "120" },
                { label: "商品价格", prop: "price", width: "" },
                { label: "订单状态", prop: "typeText", width: "" },
                { label: "用户id", prop: "userid", width: "" },
            ],
            column2: [
                { label: "用户昵称", prop: "user.nickName", width: "200" },
                { label: "真实姓名", prop: "user.realname", width: "120" },
                { label: "联系电话", prop: "user.phone", width: "" },
                { label: "第二联系电话", prop: "user.twophone", width: "" },
            ],
            tableData: [],
            
            pageNumber: 1,
            pageSize: 5,
            total: 0,
            statusMap: {
                1: "待入库",
                2: "已入库",
                3: "申请发货",
                4: "待付尾款",
                5: "待发货",
                6: "已发货",
            },
            
            currentRow: {},
            dialogVisible: false,
            dialogVisible2: false,
            
            form: {
                agentFee: '',
                jpPostage: '',
                internationalPostage: '',
                storageCharge: '',
                packingCharge: '',
                otherCharge: '',
                otherChargeMarks: '',
            },
            
            sendForm: {
                expressDeliveryCompany: '',
                expressDeliveryNo: '',
                remarks: '',
            }
        }
    },
    created(){
        this.queryMercariOrderList()
    },
    methods: {
        async onSendFormSubmit(){
            this.loading = true
            const params = {
                wlcompany: this.sendForm.expressDeliveryCompany,
                trackingNumber: this.sendForm.expressDeliveryNo,
                wlRemarks: this.sendForm.remarks,
                userid: this.currentRow.userid,
                id: this.currentRow.id,
            }
            const res = await sendGood(params)
            const {code, data, msg} = res
            if(code === 0){
                this.$message.success('操作成功')
                this.dialogVisible2 = false
                this.queryMercariOrderList()
            }else{
                this.$message.error(msg)
            }
            this.loading = false
        },
        handleClose2(){
            this.dialogVisible2 = false
        },
        onSubmit(){
            const count =   (this.form.agentFee * 100)
                            + 
                            (this.form.jpPostage * 100)
                            + 
                            (this.form.internationalPostage * 100)
                             + 
                            (this.form.storageCharge * 100)
                             + 
                            (this.form.packingCharge * 100)
                             + 
                            (this.form.otherCharge * 100)
            this.$confirm(`共计费用${parseInt(count) / 100}元，是否确认结算`, '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).then(async () => {
                this.loading = true
                const params = {
                    dgPrice: this.form.agentFee * 1 || 0,
                    jpyunfei: this.form.jpPostage * 1 || 0,
                    gjyunfei: this.form.internationalPostage * 1 || 0,
                    cangcufei: this.form.storageCharge * 1 || 0,
                    baozhuangfei: this.form.packingCharge * 1 || 0,
                    otherPrice: this.form.otherCharge * 1 || 0,
                    otherPriceContent: this.form.otherChargeMarks,
                    id: this.currentRow.id,
                    userid: this.currentRow.userid,
                }
                const res = await countCost(params)
                const {code, data, msg} = res
                if(code === 0){
                    this.$message.success('操作成功')
                    this.dialogVisible = false
                    this.queryMercariOrderList()
                }else{
                    this.$message.error(msg)
                }
                this.loading = false
            }).catch(() => {
                this.$message({
                    type: 'info',
                    message: '已取消操作'
                });          
            });
        },
        changeStatus(id, type, userid){
            this.$confirm('此操作将更改订单状态, 是否继续?', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).then(async () => {
                this.loading = true
                const params = {
                    type,
                    id,
                    userid
                }
                const res = await updataMercariOrderStatus(params)
                const {code, data, msg} = res
                if(code === 0){
                    this.$message.success('操作成功')
                    this.queryMercariOrderList()
                }else{
                    this.$message.error(msg)
                }
                this.loading = false
            }).catch(() => {
                this.$message({
                    type: 'info',
                    message: '已取消操作'
                });          
            });
        },
        showForm(row){
            this.form.agentFee = ''
            this.form.jpPostage = ''
            this.form.internationalPostage = ''
            this.form.storageCharge = ''
            this.form.packingCharge = ''
            this.form.otherCharge = ''
            this.form.otherChargeMarks = ''
            this.currentRow = row
            this.dialogVisible = true
        },
        showSendForm(row){
            
            this.sendForm.expressDeliveryCompany = ''
            this.sendForm.expressDeliveryNo = ''
            this.sendForm.remarks = ''
            
            this.currentRow = row
            this.dialogVisible2 = true
        },
        handleClose(){
            this.dialogVisible = false
        },
        async queryMercariOrderList(){
            this.loading = true
            const params = {
                pageNumber: this.pageNumber,
                pageSize: this.pageSize,
            }
            const res = await queryMercariOrderList(params)
            const {code, data, msg} = res
            if(code === 0){
                this.tableData = data.list.map((item, index)=>{
                    return {
                        ...item,
                        index: index + 1,
                        typeText: this.statusMap[item.type]
                    }
                })
                console.log(this.tableData)
                this.total = data.totalData
            }else{
                this.$message.error(msg)
            }
            this.loading = false
        },
        handleSizeChange(val) {
            this.pageSize = val
            this.queryMercariOrderList()
        },
        handleCurrentChange(val) {
            this.pageNumber = val
            this.queryMercariOrderList()
        }
    }
}
</script>
  
<style lang="scss" scoped>
::v-deep input::-webkit-outer-spin-button, ::v-deep input::-webkit-inner-spin-button{
    -webkit-appearance: none !important;
    -moz-appearance: none !important;
    -o-appearance: none !important;
    -ms-appearance: none !important;
    appearance: none !important;
    margin: 0;
}
::v-deep input[type="number"]{
    -webkit-appearance:textfield;
    -moz-appearance:textfield;
    -o-appearance:textfield;
    -ms-appearance:textfield;
    appearance:textfield;
}

::v-deep .el-table__row td:nth-child(2){
    .cell{
        padding-left: 30px;
    }
}

::v-deep .el-table__expand-icon{
    position: absolute;
    left: 10px;
}
::v-deep  .el-table__indent{
    display: none;
}
</style>
  